function solve(s) {
    const n = s.length;

    // Iterate through all possible indices i from 0 up to n-1
    for (let i = 0; i < n; i++) {
        // Calculate the corresponding index from the end
        const j = n - 1 - i;

        // Check the condition: s[i] == s[n - i - 1]
        if (s[i] === s[j]) {
            // Since we iterate starting from i=0, the first match found is the smallest index
            return i;
        }
    }

    // If no such index is found after checking all possibilities
    return -1;
}
